import sys

class Solution:
    def solve(self, arr: list[int], K: int) -> bool:
        memo = {}
        def dfs(i, current_sum):
            if current_sum == K:
                return True
            if i >= len(arr):
                return False
            state = (i, current_sum)
            if state in memo:
                return memo[state]
            res = dfs(i + 1, current_sum + arr[i]) or dfs(i + 1, current_sum)
            memo[state] = res
            return res
        return dfs(0, 0)

if __name__ == '__main__':
