#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    struct Hash {
        size_t operator()(const pair<int, int>& p) const {
            return hash<int>()(p.first) ^ (hash<int>()(p.second) << 1);
        }
    };
    unordered_map<pair<int, int>, bool, Hash> memo;

    bool dfs(const vector<int>& arr, int i, int current_sum, int K) {
        if (current_sum == K) return true;
        if (i >= arr.size()) return false;
        pair<int, int> state = {i, current_sum};
        if (memo.count(state)) return memo[state];
        bool res = dfs(arr, i + 1, current_sum + arr[i], K) || dfs(arr, i + 1, current_sum, K);
        return memo[state] = res;
    }

public:
    bool solve(vector<int>& arr, int K) {
        memo.clear();
        return dfs(arr, 0, 0, K);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    int K;
    if (!(cin >> K)) return 0;
    Solution sol;
    bool ans = sol.solve(arr, K);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
